package org.unicitylabs.sdk.api.bft;

import org.junit.jupiter.api.Assertions;
import org.junit.jupiter.api.Test;
import org.unicitylabs.sdk.util.HexConverter;

public class UnicityCertificateTest {

  @Test
  public void testUnicityCertificateDeserializationFromCbor() {
    byte[] data = HexConverter.decode(
        "");
    UnicityCertificate unicityCertificate = UnicityCertificate.fromCbor(data);

    Assertions.assertEquals(
        "",
        HexConverter.encode(unicityCertificate.toCbor())
    );
  }

}
